solution_code:
#include <iostream>

class Invoice
{
protected:
    int m_subtotal{};

public:
    Invoice(int subtotal)
        : m_subtotal{ subtotal }
    {
    }

    void print() const
    {
        std::cout << "Subtotal: " << m_subtotal << '\n';
    }
};

class TaxedInvoice : public Invoice
{
    int m_rate{};

public:
    TaxedInvoice(int subtotal, int rate)
        : Invoice{ subtotal }, m_rate{ rate }
    {
    }

    void print() const
    {
        Invoice::print();
        std::cout << "Total with tax: "
                  << m_subtotal + m_subtotal * m_rate / 100 << '\n';
    }
};

int main()
{
    int subtotal{};
    int rate{};
    std::cin >> subtotal >> rate;

    TaxedInvoice inv{ subtotal, rate };
    inv.print();

    return 0;
}

