solution_code:
#include <iomanip>
#include <iostream>

class Shape
{
protected:
    double m_width{};
    double m_height{};

public:
    Shape(double width, double height)
        : m_width{ width }, m_height{ height }
    {
    }

    double area() const { return m_width * m_height; }

    void report() const
    {
        std::cout << std::fixed << std::setprecision(1);
        std::cout << "Shape area: " << area() << '\n';
    }
};

class Rectangle : public Shape
{
public:
    Rectangle(double width, double height)
        : Shape{ width, height }
    {
    }

    void report() const
    {
        Shape::report();
        std::cout << std::fixed << std::setprecision(1);
        std::cout << "Rectangle " << m_width << " x " << m_height << '\n';
    }
};

int main()
{
    double width{};
    double height{};
    std::cin >> width >> height;

    Rectangle rect{ width, height };
    rect.report();

    return 0;
}
